[FormControlEventHandler(formControlStr(LedgerJournalTransVendInvoice, LedgerJournalTrans_ETGVendInvoiceTransRecId), FormControlEventType::Lookup)]
public static void LedgerJournalTrans_ETGVendInvoiceTransRecId_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormDataSource     ledgerJournalTransDS = sender.formRun().dataSource(formDataSourceStr(LedgerJournalTransVendInvoice, LedgerJournalTrans));
    LedgerJournalTrans ledgerJournalTrans   = ledgerJournalTransDS.cursor() as LedgerJournalTrans;

    SysReferenceTableLookup sysTableLookup = SysReferenceTableLookup::newParameters(tableNum(VendInvoiceTrans),   sender);
    // SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(VendInvoiceTrans), sender);
    Query query = new Query();
    QueryBuildDataSource qbds = query.addDataSource(tableNum(VendInvoiceTrans));
    //QueryBuildDataSource qbdsVendInvoiceJour =  qbds.addDataSource(tableNum(VendInvoiceJour));
    //qbdsVendInvoiceJour.relations(true);
    //qbdsVendInvoiceJour.joinMode(JoinMode::InnerJoin);
    // sysTableLookup.addLookupField(fieldNum(VendInvoiceJour, InvoiceAccount));
    sysTableLookup.addLookupField(fieldNum(VendInvoiceTrans, InvoiceId));
    sysTableLookup.addLookupField(fieldNum(VendInvoiceTrans, InvoiceDate));
    sysTableLookup.addLookupField(fieldNum(VendInvoiceTrans, ItemId));
    sysTableLookup.addLookupField(fieldNum(VendInvoiceTrans, Qty));
    sysTableLookup.addLookupField(fieldNum(VendInvoiceTrans, LineAmount));
    sysTableLookup.addLookupField(fieldNum(VendInvoiceTrans, CurrencyCode));
    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
    FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;
    if (ce != null)
    {
        ce.CancelSuperCall();
    }
}

