/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LedgerJournalTransVendInvoice, ETGProvisionalCharges_ETGCustVendInvJournalChargeCode), FormControlEventType::Lookup)]
public static void ETGProvisionalCharges_ETGCustVendInvJournalChargeCode_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormDataSource     ledgerJournalTransDS = sender.formRun().dataSource(formDataSourceStr(LedgerJournalTransVendInvoice, LedgerJournalTrans));
    LedgerJournalTrans ledgerJournalTrans   = ledgerJournalTransDS.cursor() as LedgerJournalTrans;

    SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(MarkupTrans), sender);
    Query query = new Query();
    QueryBuildDataSource qbds = query.addDataSource(tableNum(MarkupTrans));
    QueryBuildRange qbr = SysQuery::findOrCreateRange(qbds, fieldNum(MarkupTrans, TransRecId));
    QueryBuildRange qbr1 = SysQuery::findOrCreateRange(qbds, fieldNum(MarkupTrans, TransTableId));
    qbr.value(queryValue(ledgerJournalTrans.ETGCustVendInvJournalRefRecId));

    if(ledgerJournalTrans.ETGCustVendInvJournalOrderType == ETGCustVendInvJournalOrderType::Purchase)
    {
        qbr.value(queryValue(ledgerJournalTrans.ETGVendInvoiceTransRecId));
        qbr1.value(queryValue(tableNum(VendInvoiceTrans)));
    }
    else if(ledgerJournalTrans.ETGCustVendInvJournalOrderType == ETGCustVendInvJournalOrderType::Sales)
    {
        qbr.value(queryValue(ledgerJournalTrans.ETGCustInvoiceTransRecId));
        qbr1.value(queryValue(tableNum(CustInvoiceTrans)));
    }

    sysTableLookup.addLookupField(fieldNum(MarkupTrans, MarkupCode), true);
    sysTableLookup.addLookupField(fieldNum(MarkupTrans, Txt));
    sysTableLookup.addLookupField(fieldNum(MarkupTrans, MarkupCategory));
    sysTableLookup.addLookupField(fieldNum(MarkupTrans, LineNum));
    sysTableLookup.addLookupField(fieldNum(MarkupTrans, CalculatedAmount));
    sysTableLookup.addLookupField(fieldNum(MarkupTrans, CurrencyCode));
    sysTableLookup.parmQuery(query);
    //   sysTableLookup.parmUseLookupValue(false);
    sysTableLookup.performFormLookup();

    FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;
    if (ce != null)
    {
        ce.CancelSuperCall();
    }
}

[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransVendInvoice, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();


    FormStringControl paymentControl = formRun.control(formRun.controlId("Payment")) as FormStringControl;


    if (paymentControl)
    {
        paymentControl.mandatory(true);
    }


    if (ETG_Parameters::find().ETGDocumentDate == NoYes::Yes)
    {
        sender.object(fieldNum(LedgerJournalTrans, ETGDocumentDate)).mandatory(true);
    }
    else
    {
        sender.object(fieldNum(LedgerJournalTrans, ETGDocumentDate)).mandatory(false);
    }
}
